changeSet.sql:
-- Primary timeline query: load messages for a chat newest-first
CREATE INDEX IF NOT EXISTS idx_message_chat_created_at
    ON message (chat_id, created_at DESC);

-- Unread message lookup: find SENT messages for a given receiver
CREATE INDEX IF NOT EXISTS idx_message_undelivered
    ON message (chat_id, status)
    WHERE status IN ('SENT', 'DELIVERED');

-- Sender index for deduplication guard
CREATE INDEX IF NOT EXISTS idx_message_sender
    ON message (sender_id);
